import{_ as d,o as r,c as a,ag as e}from"./chunks/framework.CQYuu_FX.js";const c=JSON.parse('{"title":"予約管理","description":"","frontmatter":{"title":"予約管理"},"headers":[],"relativePath":"tenant/24-reservations.md","filePath":"tenant/24-reservations.md"}'),l={name:"tenant/24-reservations.md"};function i(h,t,o,n,b,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="_24-予約管理" tabindex="-1">24. 予約管理 <a class="header-anchor" href="#_24-予約管理" aria-label="Permalink to &quot;24. 予約管理&quot;">​</a></h1><p>POSLA の予約管理は、Web予約・電話予約・当日受付・待ち客・着席中・キャンセル待ち・予約金・リマインド通知を、店舗の運用画面でまとめて確認するための機能です。</p><p>この章では、お客様向け予約と店舗側の予約ボードの使い方を説明します。</p><h2 id="予約管理でできること" tabindex="-1">予約管理でできること <a class="header-anchor" href="#予約管理でできること" aria-label="Permalink to &quot;予約管理でできること&quot;">​</a></h2><table tabindex="0"><thead><tr><th>機能</th><th>内容</th></tr></thead><tbody><tr><td>Web予約受付</td><td>お客様が日時・人数・連絡先を入力して予約できます</td></tr><tr><td>電話・店頭予約登録</td><td>店舗側で予約を手入力できます</td></tr><tr><td>当日受付ボード</td><td>予約、飛び込み、待ち、着席中を同じ画面で確認できます</td></tr><tr><td>空席判定</td><td>営業時間、席、既存予約、待ち客の仮押さえを考慮して空き枠を判定します</td></tr><tr><td>キャンセル待ち</td><td>満席時にキャンセル待ち登録し、空きが出たら候補へ案内できます</td></tr><tr><td>予約金</td><td>条件に応じて予約金を求める運用ができます</td></tr><tr><td>リマインド通知</td><td>24時間前・2時間前の予約リマインドを送れます</td></tr><tr><td>常連情報</td><td>前回来店、好み、注意点、アレルギー、VIP、ブラックリストを確認できます</td></tr><tr><td>変更履歴</td><td>日時・人数・席・メモ・ステータスなどの変更前後を確認できます</td></tr></tbody></table><h2 id="利用前に確認する設定" tabindex="-1">利用前に確認する設定 <a class="header-anchor" href="#利用前に確認する設定" aria-label="Permalink to &quot;利用前に確認する設定&quot;">​</a></h2><p>予約設定では、次の内容を設定できます。</p><table tabindex="0"><thead><tr><th>設定</th><th>内容</th></tr></thead><tbody><tr><td>Web予約有効</td><td>お客様向け予約受付を有効にするか</td></tr><tr><td>受付リードタイム</td><td>何時間前まで予約を受け付けるか</td></tr><tr><td>受付可能日数</td><td>何日先まで予約を受け付けるか</td></tr><tr><td>標準滞在時間</td><td>予約1件あたりの席利用時間</td></tr><tr><td>予約枠間隔</td><td>15分、30分など予約枠の間隔</td></tr><tr><td>最小・最大人数</td><td>Web予約で受け付ける人数範囲</td></tr><tr><td>営業時間</td><td>Web予約で表示する開始・終了時刻</td></tr><tr><td>ラストオーダー前締切</td><td>閉店前の予約受付をどこで止めるか</td></tr><tr><td>定休日</td><td>Web予約を受け付けない曜日</td></tr><tr><td>前後バッファ</td><td>席の入れ替え時間を確保するための前後余白</td></tr><tr><td>電話番号・メール必須</td><td>お客様入力で必須にする項目</td></tr><tr><td>キャンセル期限</td><td>お客様が自分でキャンセルできる期限</td></tr><tr><td>Web予約枠ルール</td><td>大人数は電話のみ、ピーク時間帯の組数・人数制限、席エリア制限</td></tr><tr><td>予約金</td><td>予約金の有効化、1人あたり金額、対象人数</td></tr><tr><td>高リスク予約金</td><td>no-show履歴、大人数、ブラックリスト近似時の自動予約金</td></tr><tr><td>リマインド</td><td>24時間前・2時間前通知、再送間隔、再送上限</td></tr><tr><td>キャンセル待ち仮押さえ</td><td>空席通知後、候補者向けに枠を保持する時間</td></tr><tr><td>SMS Webhook</td><td>外部SMSサービスへ通知を連携するURL</td></tr><tr><td>AI予約</td><td>お客様の自然文入力から予約内容を読み取る機能</td></tr></tbody></table><h2 id="お客様の-web予約手順" tabindex="-1">お客様の Web予約手順 <a class="header-anchor" href="#お客様の-web予約手順" aria-label="Permalink to &quot;お客様の Web予約手順&quot;">​</a></h2><ol><li>お客様が予約ページを開きます。</li><li>日付・人数を選びます。</li><li>空いている時間枠を選びます。</li><li>名前・電話番号・メールアドレス・メモを入力します。</li><li>内容を確認して予約します。</li><li>予約完了後、予約詳細ページのURLが発行されます。</li></ol><p>予約詳細ページでは、予約内容の確認、予約金の支払い、予定のカレンダー追加、予約変更、キャンセルができます。予約変更やキャンセルは、店舗のキャンセル期限設定と予約状態によって制限されます。</p><h2 id="空席判定の考え方" tabindex="-1">空席判定の考え方 <a class="header-anchor" href="#空席判定の考え方" aria-label="Permalink to &quot;空席判定の考え方&quot;">​</a></h2><p>POSLA は予約枠を表示するときに、次の条件を確認します。</p><table tabindex="0"><thead><tr><th>判定項目</th><th>内容</th></tr></thead><tbody><tr><td>営業日・営業時間</td><td>定休日、開始時刻、終了時刻、ラストオーダー前締切</td></tr><tr><td>リードタイム</td><td>直前すぎる予約を受け付けない</td></tr><tr><td>最大受付日数</td><td>遠すぎる日付を受け付けない</td></tr><tr><td>人数制限</td><td>最小・最大人数の範囲内か</td></tr><tr><td>既存予約</td><td>確定済み・保留中など有効な予約と重ならないか</td></tr><tr><td>席の空き</td><td>1卓、2卓結合、3卓結合までの範囲で割り当て可能か</td></tr><tr><td>待ち客の仮押さえ</td><td>キャンセル待ち候補に保持している枠を重複して出さない</td></tr><tr><td>前後バッファ</td><td>前後の予約と入れ替え時間を確保できるか</td></tr><tr><td>Web予約枠ルール</td><td>大人数の電話誘導、ピーク時間帯の組数・人数制限、席エリア制限</td></tr></tbody></table><p>同じ時間・同じ席に過剰に予約が入らないよう、予約作成時にもサーバー側で再確認します。画面に表示された後に別のお客様が先に予約した場合は、作成時に満席として扱われます。</p><h2 id="満席時のキャンセル待ち" tabindex="-1">満席時のキャンセル待ち <a class="header-anchor" href="#満席時のキャンセル待ち" aria-label="Permalink to &quot;満席時のキャンセル待ち&quot;">​</a></h2><p>空き枠がない場合、条件によってキャンセル待ち登録ができます。</p><p>キャンセル待ちに登録されると、店舗側の予約ボードに候補として表示されます。キャンセルや no-show が出た場合、条件に合う候補へ空席案内を送れます。空席案内時には、設定された時間だけ候補者向けに枠を仮押さえします。</p><p>現在の空席案内は、メールアドレスがある候補者へのメール送信を前提にしています。</p><h2 id="店舗側の予約ボード" tabindex="-1">店舗側の予約ボード <a class="header-anchor" href="#店舗側の予約ボード" aria-label="Permalink to &quot;店舗側の予約ボード&quot;">​</a></h2><p>予約ボードでは、当日の予約状況を確認します。</p><p>予約管理の画面内には、次のタブがあります。</p><table tabindex="0"><thead><tr><th>タブ</th><th>内容</th></tr></thead><tbody><tr><td>予約台帳</td><td>日付別の予約、Walk-in、受付待ち、着席中、要対応、ガント表示を確認</td></tr><tr><td>顧客台帳</td><td>常連情報、前回来店、好み、注意点、アレルギー、VIP、ブラックリストを確認・編集</td></tr><tr><td>コース管理</td><td>予約で選べるコースを登録・編集</td></tr><tr><td>予約設定</td><td>Web予約、リードタイム、席ルール、予約金、リマインド、SMS Webhookを設定</td></tr><tr><td>予約レポート</td><td>Web、電話、Walk-in、AI、キャンセル、no-showなどの集計を確認</td></tr></tbody></table><p>予約台帳には表示密度の切替があります。画面幅や混雑度に応じて、コンパクト、標準、ゆったりの表示を使い分けます。予約詳細は、画面幅がある端末では右側ドロワーとして表示されます。</p><table tabindex="0"><thead><tr><th>表示</th><th>内容</th></tr></thead><tbody><tr><td>予約一覧</td><td>時刻、人数、名前、連絡先、メモ、ステータス</td></tr><tr><td>タイムライン</td><td>予約時間と席の利用状況</td></tr><tr><td>待ち客・キャンセル待ち</td><td>待機中、通知済み、呼び出し状況</td></tr><tr><td>着席状況</td><td>予約から着席へ進めたお客様</td></tr><tr><td>要対応リスト</td><td>遅刻、no-show履歴、ブラックリスト、大人数、通知失敗など</td></tr><tr><td>常連情報</td><td>前回来店、好み、注意点、アレルギー、タグ</td></tr><tr><td>変更履歴</td><td>誰が、いつ、何を、変更前後どう変えたか</td></tr></tbody></table><p>遅刻中、no-show履歴あり、ブラックリスト、大人数などはリスクとして表示され、電話確認や予約金検討などの対応候補が分かるようになっています。</p><h3 id="当日受付・walk-in・受付待ち" tabindex="-1">当日受付・Walk-in・受付待ち <a class="header-anchor" href="#当日受付・walk-in・受付待ち" aria-label="Permalink to &quot;当日受付・Walk-in・受付待ち&quot;">​</a></h3><p>当日の店頭受付は、予約台帳から登録できます。</p><table tabindex="0"><thead><tr><th>ボタン</th><th>用途</th></tr></thead><tbody><tr><td>+ 新規予約</td><td>電話予約や店頭で受けた通常予約を登録</td></tr><tr><td>+ Walk-in</td><td>予約なしで来店したお客様を登録</td></tr><tr><td>+ 受付待ち</td><td>席が空くまで待つお客様を受付待ちとして登録</td></tr></tbody></table><p>受付待ちは、通常予約のガント時間軸には載せず、受付待ちパネルに表示されます。席が空いたら、対象の受付待ちから <strong>着席</strong> を押してテーブルを指定します。</p><h3 id="要対応リスト" tabindex="-1">要対応リスト <a class="header-anchor" href="#要対応リスト" aria-label="Permalink to &quot;要対応リスト&quot;">​</a></h3><p>要対応リストには、次のような予約が集約されます。</p><ul><li>テーブル未割当</li><li>予約時刻を過ぎた保留・確定予約</li><li>遅刻リスク</li><li>リマインド送信対象または送信失敗</li><li>no-show履歴や大人数などのリスク予約</li><li>顧客台帳に注意点、アレルギー、ブラックリストがある予約</li></ul><p>要対応が出た場合は、予約詳細を開き、電話確認、来店フォロー、席変更、リマインド再送、no-show処理などを行ってください。</p><h2 id="予約ステータス" tabindex="-1">予約ステータス <a class="header-anchor" href="#予約ステータス" aria-label="Permalink to &quot;予約ステータス&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ステータス</th><th>意味</th></tr></thead><tbody><tr><td>保留</td><td>予約受付後、確定前の状態</td></tr><tr><td>確定</td><td>来店予定として確定している状態</td></tr><tr><td>着席中</td><td>お客様を席へ案内した状態</td></tr><tr><td>no-show</td><td>無断キャンセルとして処理した状態</td></tr><tr><td>キャンセル</td><td>キャンセル済み</td></tr><tr><td>完了</td><td>来店完了</td></tr><tr><td>キャンセル待ち</td><td>空席待ちの状態</td></tr></tbody></table><p>no-show 処理をすると、顧客情報の no-show 回数に反映されます。予約金の与信がある予約では、設定と決済状態に応じて予約金の捕捉処理が行われます。</p><h2 id="変更履歴・変更前後比較" tabindex="-1">変更履歴・変更前後比較 <a class="header-anchor" href="#変更履歴・変更前後比較" aria-label="Permalink to &quot;変更履歴・変更前後比較&quot;">​</a></h2><p>予約の詳細画面では、変更履歴を確認できます。</p><p>記録対象には、主に次の項目があります。</p><ul><li>顧客名、電話番号、メールアドレス</li><li>人数</li><li>予約日時</li><li>滞在時間</li><li>メモ</li><li>タグ</li><li>コース</li><li>割り当て席</li><li>ステータス</li><li>来店フォロー状態</li><li>キャンセル待ち呼び出し状態</li></ul><p>履歴には、変更者、変更日時、変更前、変更後が残ります。予約トラブル時は、まず詳細画面の変更履歴を確認してください。</p><h2 id="リマインド通知" tabindex="-1">リマインド通知 <a class="header-anchor" href="#リマインド通知" aria-label="Permalink to &quot;リマインド通知&quot;">​</a></h2><p>予約リマインドは、設定により 24時間前・2時間前に送信できます。</p><p>通知経路は、店舗設定とお客様情報に応じて使われます。</p><table tabindex="0"><thead><tr><th>経路</th><th>条件</th></tr></thead><tbody><tr><td>メール</td><td>お客様メールアドレスがあり、送信設定がある場合</td></tr><tr><td>LINE</td><td>店舗の LINE 連携が有効で、お客様のLINE紐付けがある場合</td></tr><tr><td>SMS Webhook</td><td>SMS連携URLが設定され、電話番号がある場合</td></tr></tbody></table><p>送信に失敗したリマインドは、設定された再送間隔と再送上限に従って再送対象になります。失敗が上限に達すると、店長が確認すべき通知として扱われます。</p><h2 id="予約金と高リスク予約" tabindex="-1">予約金と高リスク予約 <a class="header-anchor" href="#予約金と高リスク予約" aria-label="Permalink to &quot;予約金と高リスク予約&quot;">​</a></h2><p>予約金を有効にすると、設定した人数以上の予約に予約金を求めることができます。予約金の決済には店舗の決済設定が必要です。</p><p>高リスク予約金を有効にした場合、次のような条件で予約金必須にできます。</p><table tabindex="0"><thead><tr><th>条件</th><th>内容</th></tr></thead><tbody><tr><td>no-show履歴</td><td>指定回数以上の no-show があるお客様</td></tr><tr><td>大人数</td><td>指定人数以上の予約</td></tr><tr><td>ブラックリスト近似</td><td>顧客情報の注意対象に近いと判定される場合</td></tr></tbody></table><p>店舗側で電話予約を作成する場合は、必要に応じて予約金をスキップする運用もできます。</p><h2 id="常連情報" tabindex="-1">常連情報 <a class="header-anchor" href="#常連情報" aria-label="Permalink to &quot;常連情報&quot;">​</a></h2><p>予約詳細では、顧客情報として次の内容を確認できます。</p><ul><li>前回来店日</li><li>来店回数</li><li>no-show 回数</li><li>キャンセル回数</li><li>累計利用金額</li><li>好み</li><li>注意点</li><li>アレルギー</li><li>VIP</li><li>ブラックリスト</li><li>タグ</li></ul><p>アレルギーや注意点は、来店前の共有事項として必ず確認してください。</p><h2 id="関連画面への表示" tabindex="-1">関連画面への表示 <a class="header-anchor" href="#関連画面への表示" aria-label="Permalink to &quot;関連画面への表示&quot;">​</a></h2><p>予約から着席したお客様の情報は、予約ボードだけでなく、ハンディ、KDS、POSレジにも表示されます。</p><table tabindex="0"><thead><tr><th>画面</th><th>確認できる内容</th></tr></thead><tbody><tr><td>ハンディ</td><td>予約者名、人数、予約時刻、メモ、好み、アレルギー、注意点、来店回数、VIP・リスク・通知未対応バッジ</td></tr><tr><td>KDS</td><td>予約者名、人数、予約時刻、コース、メモ、好み、注意点、来店回数、予約アレルギー</td></tr><tr><td>POSレジ</td><td>予約者名、人数、予約時刻、コース、メモ、好み、アレルギー、注意点、来店回数</td></tr></tbody></table><p>厨房、ホール、会計で同じ予約文脈を確認できるため、アレルギー対応、常連対応、会計時の声かけを引き継ぎやすくなります。</p><h2 id="ai予約" tabindex="-1">AI予約 <a class="header-anchor" href="#ai予約" aria-label="Permalink to &quot;AI予約&quot;">​</a></h2><p>AI予約を有効にしている場合、お客様が自然文で希望内容を入力し、日時・人数・名前・連絡先などの読み取り補助を受けられます。</p><p>AIが読み取った内容は、予約作成前にお客様が確認します。空席判定、予約金、高リスク判定は通常のWeb予約と同じサーバー側処理で確認されます。</p><h2 id="当日の基本運用" tabindex="-1">当日の基本運用 <a class="header-anchor" href="#当日の基本運用" aria-label="Permalink to &quot;当日の基本運用&quot;">​</a></h2><ol><li>営業前に当日の予約ボードを開きます。</li><li>要対応リストで、遅刻リスク・no-show履歴・大人数・通知失敗を確認します。</li><li>必要に応じて電話確認、予約金確認、席調整を行います。</li><li>来店したお客様を着席に進めます。</li><li>遅刻している予約は来店フォロー状態を更新します。</li><li>no-show が確定した場合は no-show 処理を行います。</li><li>キャンセルや no-show で空きが出たら、キャンセル待ち候補を確認します。</li></ol><h2 id="よくあるトラブル" tabindex="-1">よくあるトラブル <a class="header-anchor" href="#よくあるトラブル" aria-label="Permalink to &quot;よくあるトラブル&quot;">​</a></h2><table tabindex="0"><thead><tr><th>困ったこと</th><th>確認すること</th></tr></thead><tbody><tr><td>Web予約枠が出ない</td><td>Web予約有効、営業時間、定休日、リードタイム、最大受付日数、席設定を確認</td></tr><tr><td>大人数だけ予約できない</td><td>Web予約枠ルールで電話のみ対象になっていないか確認</td></tr><tr><td>ピーク時間だけ満席になる</td><td>ピーク最大組数・最大人数の設定を確認</td></tr><tr><td>リマインドが届かない</td><td>メール、LINE紐付け、SMS Webhook、通知失敗・再送状態を確認</td></tr><tr><td>予約金が求められない</td><td>決済設定、予約金有効、対象人数、高リスク予約金設定を確認</td></tr><tr><td>キャンセル待ち通知が届かない</td><td>候補者のメールアドレス、空席条件、仮押さえ期限を確認</td></tr><tr><td>何が変更されたか分からない</td><td>予約詳細の変更履歴・変更前後比較を確認</td></tr></tbody></table>',67)])])}const u=d(l,[["render",i]]);export{c as __pageData,u as default};
